### Implementing the Checkers Game

```python
import pygame
import sys

# Define constants for the game
WIDTH, HEIGHT = 500, 500
SQUARE_SIZE = WIDTH // 8
BOARD_ROWS = 8
BOARD_COLS = 8
RED = (255, 0, 0)
WHITE = (255, 255, 255)
BLUE = (0, 0, 255)

class Piece:
    def __init__(self, row, col, color):
        self.row = row
        self.col = col
        self.color = color
        self.king = False
        self.selected = False

    def move(self, row, col):
        self.row = row
        self.col = col

    def make_king(self):
        self.king = True

    def draw_piece(self, win):
        radius = SQUARE_SIZE // 2 - 20
        pygame.draw.circle(win, BLUE, (self.col * SQUARE_SIZE + SQUARE_SIZE // 2, self.row * SQUARE_SIZE + SQUARE_SIZE // 2), radius)
        if self.king:
            pygame.draw.circle(win, WHITE, (self.col * SQUARE_SIZE + SQUARE_SIZE // 2, self.row * SQUARE_SIZE + SQUARE_SIZE // 2), radius - 10)

class Board:
    def __init__(self):
        self.board = []
        self.init_board()

    def draw(self, win):
        win.fill(WHITE)
        for row in range(BOARD_ROWS):
            for col in range(row % 2, BOARD_COLS, 2):
                pygame.draw.rect(win, BLUE, (row * SQUARE_SIZE, col * SQUARE_SIZE, SQUARE_SIZE, SQUARE_SIZE))

    def init_board(self):
        self.board = []
        for row in range(BOARD_ROWS):
            self.board.append([])
            for col in range(BOARD_COLS):
                if (col + row) % 2 == 1:
                    self.board[row].append(Piece(row, col, RED))
                else:
                    self.board[row].append(None)

class Game:
    def __init__(self, win):
        self._init()
        self.win = win

    def _init(self):
        self.selected_piece = None
        self.board = Board()

    def update(self):
        pygame.display.update()

    def draw(self):
        self.board.draw(self.win)

def main():
    pygame.init()
    win = pygame.display.set_mode((WIDTH, HEIGHT))
    game = Game(win)
    run = True

    while run:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                run = False
                pygame.quit()
                sys.exit()

            if event.type == pygame.MOUSEBUTTONDOWN:
                pos = pygame.mouse.get_pos()
                row, col = pos[1] // SQUARE_SIZE, pos[0] // SQUARE_SIZE
                game.select(row, col)

        game.draw()
        pygame.display.update()

if __name__ == "__main__":
    main()
```

